import java.util.*;

// User-defined class implementing Comparable for natural ordering
class Student implements Comparable<Student> {
 private int rollNo;
 private String name;
 private double GPA;

 // Constructor
 public Student(int rollNo, String name, double GPA) {
 this.rollNo = rollNo;
 this.name = name;
 this.GPA = GPA;
 }

 // Getters
 public int getRollNo() { return rollNo; }
 public String getName() { return name; }
 public double getGPA() { return GPA; }

 // Override equals() - defines equality based on rollNo
 @Override
 public boolean equals(Object obj) {
 // Check for null
 if (obj == null) return false;
 // Check for same reference
 if (this == obj) return true;
 // Check same class
 if (getClass() != obj.getClass()) return false;

 Student other = (Student) obj;
 // Equality based on rollNo only
 return this.rollNo == other.rollNo;
 }

 // Override hashCode() - must be consistent with equals()
 @Override
 public int hashCode() {
 // Using Objects.hash() for multiple fields
 return Objects.hash(rollNo);
 // Can also use: return Integer.hashCode(rollNo);
 }

 // Override compareTo() - defines natural ordering by rollNo
 @Override
 public int compareTo(Student other) {
 return Integer.compare(this.rollNo, other.rollNo);
 }

 @Override
 public String toString() {
 return "Student{rollNo=" + rollNo + ", name='" + name + "', GPA=" + GPA + "}";
 }
}

public class StudentCollectionsDemo {
 public static void main(String[] args) {
 Student s1 = new Student(101, "Alice", 3.8);
 Student s2 = new Student(102, "Bob", 3.5);
 Student s3 = new Student(101, "Charlie", 3.9); // Same rollNo as s1

 // === ArrayList - stores elements in insertion order ===
 System.out.println("=== ArrayList Demo ===");
 ArrayList<Student> studentList = new ArrayList<>();
 studentList.add(s1);
 studentList.add(s2);
 studentList.add(s3);
 System.out.println("List: " + studentList);
 System.out.println("Contains s1: " + studentList.contains(s1)); // Uses equals()

 // === HashSet - uses equals() and hashCode() for uniqueness ===
 System.out.println("\n=== HashSet Demo ===");
 HashSet<Student> studentSet = new HashSet<>();
 studentSet.add(s1);
 studentSet.add(s2);
 studentSet.add(s3); // Won't add - same rollNo as s1
 System.out.println("Set size: " + studentSet.size()); // 2, not 3
 System.out.println("Set: " + studentSet);

 // === TreeSet - uses compareTo() for sorting and uniqueness ===
 System.out.println("\n=== TreeSet Demo ===");
 TreeSet<Student> studentTreeSet = new TreeSet<>();
 studentTreeSet.add(s1);
 studentTreeSet.add(s2);
 studentTreeSet.add(s3); // Won't add - considered equal by compareTo()
 System.out.println("TreeSet (sorted): " + studentTreeSet);

 // === HashMap - uses equals() and hashCode() for keys ===
 System.out.println("\n=== HashMap Demo ===");
 HashMap<Student, String> studentMap = new HashMap<>();
 studentMap.put(s1, "Scholarship");
 studentMap.put(s2, "None");
 studentMap.put(s3, "Grant"); // Overwrites s1's value (same key)
 System.out.println("Map: " + studentMap);
 System.out.println("Value for s1: " + studentMap.get(s1));

 // === Demonstrating equals() with different objects ===
 Student s4 = new Student(101, "Diana", 4.0); // Same rollNo as s1
 System.out.println("\n=== Equality Check ===");
 System.out.println("s1.equals(s3): " + s1.equals(s3)); // true (same rollNo)
 System.out.println("s1.equals(s4): " + s1.equals(s4)); // true (same rollNo)
 System.out.println("s1.hashCode() == s3.hashCode(): " + (s1.hashCode() == s3.hashCode()));
 }
}
